public void  delete()
{
    ETG_IsCreatedAgreement       isCreatedAgreement;
    ETG_AgreementLineNotes       agreementLineNotes;
    RefRecId                     refRecId;

    refRecId = this.RecId;
    next delete();

    delete_from isCreatedAgreement
        where isCreatedAgreement.AgreementLine == refRecId;

    delete_from agreementLineNotes
        where agreementLineNotes.AgreementLine == refRecId;

}

/// <summary>
/// initialize mandatory fields after item selection
/// </summary>
/// <param name = "_inventTable">InventTable _inventTable</param>
public void initFromInventTable(InventTable _inventTable)
{
    next initFromInventTable(_inventTable);

    if(ETGACFParameters::find().EnableExpirationDateOptionalContracts == NoYes::Yes)
    {
        this.ExpirationDate = this.agreementHeader().DefaultAgreementLineExpirationDate;
    }
}

